                                      `tenant_id` varchar(12) DEFAULT '000000' COMMENT '租户ID',
                                      PRIMARY KEY (`id`),
                                      UNIQUE KEY `WF_IDX_EXPRESSION` (`expression`,`type`,`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='流程表达式';

