INSERT INTO `blade_wf_form` (`id`, `form_key`, `name`, `content`, `app_content`, `version`, `category_id`, `remark`, `create_user`, `create_dept`, `create_time`, `update_user`, `update_time`, `status`, `is_deleted`, `tenant_id`) VALUES (1399729025840140290, 'leave', '请假流程表单', '{column:[{type:\'input\',label:\'创建人\',span:12,display:true,prop:\'creator\',value:\'${this.$store.getters.userInfo.nick_name}\',readonly:true},{type:\'input\',label:\'创建部门\',span:12,display:true,prop:\'creatorDept\',value:\'${this.$store.getters.userInfo.dept_name}\',readonly:true},{type:\'datetimerange\',label:\'请假时间\',span:12,display:true,format:\'YYYY-MM-DD HH:mm:ss\',valueFormat:\'YYYY-MM-DD HH:mm:ss\',prop:\'datetime\',required:true,rules:[{required:true,message:\'请假时间必须填写\'}],change:({value}) => {\r\n  let days\r\n  if (!value || value.length == 0) {\r\n    days = undefined\r\n  } else {\r\n    const d1 = Date.parse(value.split(\',\')[0])\r\n    const d2 = Date.parse(value.split(\',\')[1])\r\n    const day = (d2-d1)/(1*24*60*60*1000)\r\n    days = Number(day.toFixed(2))\r\n  }\r\n  this.form.days = days\r\n},dataType:\'string\'},{type:\'number\',label:\'请假天数\',span:12,display:true,prop:\'days\',required:true,rules:[{required:true,message:\'请假天数必须填写\'}],controls:true,controlsPosition:\'right\',change:({value}) => {\n  let reason\n  if (value) reason = \'请假\' + value + \'天\'\n  else reason = \'\'\n  this.form.reason = reason\n}},{type:\'textarea\',label:\'请假理由\',span:24,display:true,prop:\'reason\',required:true,rules:[{required:true,message:\'请假理由必须填写\'}]},{label:\'附件\',type:\'upload\',propsHttp:{res:\'data\',url:\'link\',name:\'originalName\'},action:\'/api/blade-resource/oss/endpoint/put-file\',display:true,span:24,showFileList:true,multiple:true,limit:10,prop:\'attachment\',dataType:\'string\'}],labelPosition:\'left\',labelSuffix:\'：\',labelWidth:120,gutter:0,menuBtn:true,submitBtn:true,submitText:\'提交\',emptyBtn:true,emptyText:\'清空\',menuPosition:\'center\'}', '{\"column\":[{\"type\":\"input\",\"label\":\"创建人\",\"span\":12,\"display\":true,\"prop\":\"creator\",\"value\":\"${this.$store.getters.userInfo.nick_name}\",\"readonly\":true},{\"type\":\"input\",\"label\":\"创建部门\",\"span\":12,\"display\":true,\"prop\":\"creatorDept\",\"value\":\"${this.$store.getters.userInfo.dept_name}\",\"readonly\":true},{\"type\":\"datetimerange\",\"label\":\"请假时间\",\"span\":12,\"display\":true,\"format\":\"YYYY-MM-DD HH:mm:ss\",\"valueFormat\":\"YYYY-MM-DD HH:mm:ss\",\"prop\":\"datetime\",\"required\":true,\"rules\":[{\"required\":true,\"message\":\"请假时间必须填写\"}],\"change\":\"({value}) => {\\r\\n  let days\\r\\n  if (!value || value.length == 0) {\\r\\n    days = undefined\\r\\n  } else {\\r\\n    const d1 = Date.parse(value.split(\',\')[0])\\r\\n    const d2 = Date.parse(value.split(\',\')[1])\\r\\n    const day = (d2-d1)/(1*24*60*60*1000)\\r\\n    days = Number(day.toFixed(2))\\r\\n  }\\r\\n  this.form.days = days\\r\\n}\",\"dataType\":\"string\"},{\"type\":\"number\",\"label\":\"请假天数\",\"span\":12,\"display\":true,\"prop\":\"days\",\"required\":true,\"rules\":[{\"required\":true,\"message\":\"请假天数必须填写\"}],\"controls\":true,\"controlsPosition\":\"right\",\"change\":\"({value}) => {\\n  let reason\\n  if (value) reason = \'请假\' + value + \'天\'\\n  else reason = \'\'\\n  this.form.reason = reason\\n}\"},{\"type\":\"textarea\",\"label\":\"请假理由\",\"span\":24,\"display\":true,\"prop\":\"reason\",\"required\":true,\"rules\":[{\"required\":true,\"message\":\"请假理由必须填写\"}]},{\"label\":\"附件\",\"type\":\"upload\",\"propsHttp\":{\"res\":\"data\",\"url\":\"link\",\"name\":\"originalName\"},\"action\":\"/api/blade-resource/oss/endpoint/put-file\",\"display\":true,\"span\":24,\"showFileList\":true,\"multiple\":true,\"limit\":10,\"prop\":\"attachment\",\"dataType\":\"string\"}],\"labelPosition\":\"left\",\"labelSuffix\":\"：\",\"labelWidth\":120,\"gutter\":0,\"menuBtn\":true,\"submitBtn\":true,\"submitText\":\"提交\",\"emptyBtn\":true,\"emptyText\":\"清空\",\"menuPosition\":\"center\"}', 1, 1642162799092207618, '', 1123598821738675201, 1123598813738675201, '2021-06-01 22:06:20', 1123598821738675201, '2023-04-09 18:03:17', 1, 0, '000000');
