-- ----------------------------
-- Table structure for blade_wf_form_variable
-- ----------------------------
DROP TABLE IF EXISTS `blade_wf_form_variable`;
CREATE TABLE `blade_wf_form_variable` (
                                          `id` bigint(64) NOT NULL,
                                          `process_ins_id` varchar(255) DEFAULT NULL COMMENT '流程实例id',
                                          `deployment_id` varchar(255) DEFAULT NULL COMMENT '流程部署id',
                                          `task_id` varchar(255) DEFAULT NULL COMMENT '任务id',
                                          `task_def_key` varchar(255) DEFAULT NULL COMMENT '任务节点key',
                                          `task_name` varchar(255) DEFAULT NULL COMMENT '任务节点名称',
                                          `form_option` longtext COMMENT '表单js',
                                          `form_variable` longtext COMMENT '表单值',
                                          `status` varchar(255) DEFAULT NULL COMMENT '状态',
                                          `create_user` bigint(64) DEFAULT NULL COMMENT '创建人',
                                          `create_time` datetime DEFAULT NULL COMMENT '创建时间',
                                          `create_dept` bigint(64) DEFAULT NULL COMMENT '创建部门',
                                          `update_user` bigint(64) DEFAULT NULL COMMENT '修改人',
                                          `update_time` datetime DEFAULT NULL COMMENT '修改时间',
                                          `is_deleted` int(2) DEFAULT '0' COMMENT '是否已删除',
                                          `tenant_id` varchar(12) DEFAULT '000000' COMMENT '租户ID',
                                          PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='流程表单 - 历史变量';

-- ----------------------------
-- Records of blade_wf_form_variable
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for blade_wf_listener
-- ----------------------------
DROP TABLE IF EXISTS `blade_wf_listener`;
CREATE TABLE `blade_wf_listener` (
                                     `id` bigint(64) NOT NULL,
                                     `name` varchar(255) DEFAULT NULL COMMENT '名称',
                                     `category` varchar(255) DEFAULT NULL COMMENT '分类',
                                     `event` varchar(255) DEFAULT NULL COMMENT '事件',
                                     `type` varchar(255) DEFAULT NULL COMMENT '监听类型',
                                     `val` varchar(255) DEFAULT NULL COMMENT '值',
                                     `create_user` bigint(64) DEFAULT NULL COMMENT '创建人',
                                     `create_dept` bigint(64) DEFAULT NULL COMMENT '创建部门',
                                     `create_time` datetime DEFAULT NULL COMMENT '创建时间',
                                     `update_user` bigint(64) DEFAULT NULL COMMENT '修改人',
                                     `update_time` datetime DEFAULT NULL COMMENT '修改时间',
                                     `status` int(11) DEFAULT NULL COMMENT '状态',
                                     `is_deleted` int(2) DEFAULT '0' COMMENT '是否已删除',
                                     `tenant_id` varchar(12) DEFAULT '000000' COMMENT '租户ID',
                                     PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='任务/执行监听器';

-- ----------------------------
-- Table structure for blade_wf_model_scope
-- ----------------------------
DROP TABLE IF EXISTS `blade_wf_model_scope`;
CREATE TABLE `blade_wf_model_scope` (
                                        `id` bigint(64) NOT NULL,
                                        `model_id` varchar(255) DEFAULT NULL COMMENT '模型id',
                                        `model_key` varchar(255) DEFAULT NULL COMMENT '模型key',
                                        `type` varchar(255) DEFAULT NULL COMMENT '类型 user用户 role角色 dept部门 post职位',
                                        `val` varchar(255) DEFAULT NULL COMMENT '用户/角色/部门/职位 id集合',
                                        `text` varchar(255) DEFAULT NULL COMMENT '用户/角色/部门/职位 name集合',
                                        PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='流程模型权限';

