-- ----------------------------
-- Table structure for blade_wf_process_leave
-- ----------------------------
DROP TABLE IF EXISTS `blade_wf_process_leave`;
CREATE TABLE `blade_wf_process_leave` (
                                          `id` bigint(64) NOT NULL,
                                          `process_ins_id` varchar(64) DEFAULT NULL COMMENT '流程实例id',
                                          `process_def_id` varchar(64) DEFAULT NULL COMMENT '流程定义id',
                                          `current_node` varchar(64) DEFAULT NULL COMMENT '当前节点',
                                          `datetime` varchar(64) DEFAULT NULL COMMENT '时间范围',
                                          `days` int(11) DEFAULT NULL COMMENT '请假天数',
                                          `reason` text COMMENT '请假理由',
                                          `attachment` text COMMENT '附件',
                                          `create_user` bigint(20) DEFAULT NULL COMMENT '创建人',
                                          `create_dept` bigint(20) DEFAULT NULL COMMENT '创建部门',
                                          `create_time` datetime NOT NULL COMMENT '创建时间',
                                          `update_user` bigint(20) DEFAULT NULL COMMENT '修改人',
                                          `update_time` datetime DEFAULT NULL COMMENT '修改时间',
                                          `status` int(2) DEFAULT NULL COMMENT '状态',
                                          `is_deleted` int(2) DEFAULT NULL COMMENT '是否已删除',
                                          `form_key` varchar(255) DEFAULT NULL COMMENT '外置表单key',
                                          `form_url` varchar(255) DEFAULT NULL COMMENT '外置表单url',
                                          PRIMARY KEY (`id`,`create_time`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='请假流程业务示例';

-- ----------------------------
-- Table structure for blade_wf_proxy
-- ----------------------------
DROP TABLE IF EXISTS `blade_wf_proxy`;
CREATE TABLE `blade_wf_proxy` (
                                  `id` bigint(64) NOT NULL,
                                  `user_id` bigint(64) DEFAULT NULL COMMENT '委托人',
                                  `proxy_user_id` bigint(64) DEFAULT NULL COMMENT '代理人',
                                  `process_def_key` varchar(750) DEFAULT NULL COMMENT '流程定义key',
                                  `type` varchar(255) DEFAULT NULL COMMENT '1永久 2定时',
                                  `start_time` datetime DEFAULT NULL COMMENT '开始时间',
                                  `end_time` datetime DEFAULT NULL COMMENT '结束时间',
                                  `status` int(2) DEFAULT NULL COMMENT '状态',
                                  PRIMARY KEY (`id`),
                                  UNIQUE KEY `WF_IDX_UNI_PROXY` (`user_id`,`process_def_key`) USING BTREE,
                                  KEY `WF_IDX_USER_ID` (`user_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='流程代理';

-- ----------------------------
-- Table structure for blade_wf_serial
-- ----------------------------
DROP TABLE IF EXISTS `blade_wf_serial`;
CREATE TABLE `blade_wf_serial` (
                                   `id` bigint(64) NOT NULL,
                                   `deployment_id` varchar(255) DEFAULT NULL COMMENT '部署id',
                                   `name` varchar(255) DEFAULT NULL COMMENT '名称',
                                   `prefix` varchar(255) DEFAULT NULL COMMENT '前缀',
                                   `date_format` varchar(255) DEFAULT NULL COMMENT '日期格式化',
                                   `suffix_length` int(11) DEFAULT NULL COMMENT '后缀位数',
                                   `start_sequence` int(11) DEFAULT NULL COMMENT '初始数值',
                                   `connector` varchar(255) DEFAULT NULL COMMENT '连接符',
                                   `current_sequence` int(11) DEFAULT NULL COMMENT '当前序列',
                                   `cycle` varchar(255) DEFAULT NULL COMMENT '重置周期 none不重置 day天 week周 month月 year年',
                                   `create_user` bigint(64) DEFAULT NULL COMMENT '创建人',
                                   `create_dept` bigint(64) DEFAULT NULL COMMENT '创建部门',
                                   `create_time` datetime DEFAULT NULL COMMENT '创建时间',
                                   `update_user` bigint(64) DEFAULT NULL COMMENT '修改人',
                                   `update_time` datetime DEFAULT NULL COMMENT '修改时间',
                                   `status` varchar(255) DEFAULT NULL COMMENT '状态',
                                   `is_deleted` int(2) DEFAULT '0' COMMENT '是否已删除',
                                   PRIMARY KEY (`id`),
                                   UNIQUE KEY `uni` (`deployment_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='流程流水号';

-- ----------------------------
-- Records of blade_wf_serial
-- ----------------------------
BEGIN;
COMMIT;

SET FOREIGN_KEY_CHECKS = 1;
